import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const PostProductPage = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [selectedCat, setSelectedCat] = useState(null);

  const [formData, setFormData] = useState({
    name: '', price: '', image: '', description: '', location: 'TP. Hồ Chí Minh'
  });
  const [details, setDetails] = useState({});

  const categories = [
    { id: 'bds', name: 'Bất động sản', icon: '🏠', questions: [{ key: 'area', label: 'Diện tích (m2)', type: 'number' }, { key: 'bedrooms', label: 'Số phòng ngủ', type: 'number' }, { key: 'direction', label: 'Hướng nhà', type: 'text' }] },
    { id: 'xe', name: 'Xe cộ', icon: '🛵', questions: [{ key: 'brand', label: 'Hãng xe', type: 'text' }, { key: 'year', label: 'Năm sản xuất', type: 'number' }, { key: 'km', label: 'Số KM đã đi', type: 'number' }] },
    { id: 'dientu', name: 'Đồ điện tử', icon: '📱', questions: [{ key: 'brand', label: 'Hãng sản xuất', type: 'text' }, { key: 'warranty', label: 'Bảo hành (tháng)', type: 'number' }, { key: 'color', label: 'Màu sắc', type: 'text' }] },
    { id: 'vieclam', name: 'Việc làm', icon: '💼', questions: [{ key: 'salary', label: 'Mức lương', type: 'text' }, { key: 'position', label: 'Vị trí công việc', type: 'text' }, { key: 'type', label: 'Hình thức', type: 'text' }] },
    { id: 'dogiadung', name: 'Đồ gia dụng', icon: '🪑', questions: [{ key: 'type', label: 'Loại đồ dùng', type: 'text' }, { key: 'material', label: 'Chất liệu', type: 'text' }, { key: 'status', label: 'Tình trạng (%)', type: 'number' }] },
    { id: 'thucung', name: 'Thú cưng', icon: '🐶', questions: [{ key: 'breed', label: 'Giống loài', type: 'text' }, { key: 'age', label: 'Độ tuổi (Tháng)', type: 'number' }, { key: 'vaccine', label: 'Tiêm phòng', type: 'text' }] }, 
  ];

  const handleSelectCategory = (cat) => { setSelectedCat(cat); setStep(2); setDetails({}); };

  const handleSubmit = async (e) => {
    e.preventDefault();
    // 👇 Lấy thông tin user
    const userInfo = JSON.parse(localStorage.getItem('userInfo'));
    if (!userInfo) { alert("Bạn chưa đăng nhập!"); return; }

    try {
      await axios.post('http://localhost:5000/api/products', {
        ...formData,
        category: selectedCat.name,
        details: details,
        userId: userInfo._id // 👇 Gửi kèm ID người dùng
      });
      alert('Đăng tin thành công!');
      navigate('/');
    } catch (error) { alert('Lỗi: ' + (error.response?.data?.message || 'Không thể đăng tin')); }
  };

  return (
    <div className="container py-4" style={{maxWidth: '800px'}}>
      <header className="d-flex align-items-center mb-4">
         <h2 className="fw-bold text-chotot m-0" style={{cursor: 'pointer'}} onClick={() => navigate('/')}>HaiHand</h2>
         <span className="ms-3 text-muted border-start ps-3">Đăng tin</span>
         <button className="btn btn-close ms-auto" onClick={() => navigate('/')}></button>
      </header>

      {step === 1 && (
        <div className="card shadow border-0 animate__animated animate__fadeInUp">
           <div className="card-header bg-white border-bottom-0 pt-4 pb-0 text-center"><h4 className="fw-bold text-primary">Bạn muốn đăng bán gì?</h4></div>
           <div className="card-body p-4"><div className="row g-3">{categories.map(cat => (<div className="col-6 col-md-4" key={cat.id}><div className="card h-100 text-center py-4 border-0 shadow-sm category-hover" style={{cursor: 'pointer', backgroundColor: '#f8f9fa'}} onClick={() => handleSelectCategory(cat)}><div style={{fontSize: '45px', marginBottom: '10px'}}>{cat.icon}</div><div className="fw-bold fs-5">{cat.name}</div></div></div>))}</div></div>
        </div>
      )}

      {step === 2 && (
        <div className="card shadow border-0 animate__animated animate__fadeIn">
          <div className="card-header bg-chotot text-dark d-flex align-items-center py-3"><button className="btn btn-sm btn-outline-dark me-3 fw-bold" onClick={() => setStep(1)}>⬅ Quay lại</button><h5 className="mb-0 fw-bold">Đăng tin: {selectedCat.name}</h5></div>
          <div className="card-body p-4">
            <form onSubmit={handleSubmit}>
              <h6 className="fw-bold text-primary mb-3">1. Thông tin chung</h6>
              <div className="mb-3"><label className="form-label fw-bold">Tiêu đề</label><input type="text" className="form-control" required onChange={(e) => setFormData({...formData, name: e.target.value})} /></div>
              <div className="row"><div className="col-md-6 mb-3"><label className="form-label fw-bold">Giá bán</label><input type="number" className="form-control" required onChange={(e) => setFormData({...formData, price: e.target.value})} /></div><div className="col-md-6 mb-3"><label className="form-label fw-bold">Khu vực</label><select className="form-select" onChange={(e) => setFormData({...formData, location: e.target.value})}><option>TP. Hồ Chí Minh</option><option>Hà Nội</option><option>Đà Nẵng</option><option>Cần Thơ</option></select></div></div>
              
              {selectedCat.questions.length > 0 && (
                <div className="bg-light p-3 rounded mb-4"><h6 className="fw-bold text-dark mb-3">2. Chi tiết</h6><div className="row">{selectedCat.questions.map(q => (<div className="col-md-6 mb-3" key={q.key}><label className="form-label">{q.label}</label><input type={q.type} className="form-control" required onChange={(e) => setDetails({...details, [q.key]: e.target.value})} /></div>))}</div></div>
              )}

              <h6 className="fw-bold text-primary mb-3">3. Hình ảnh & Mô tả</h6>
              <div className="mb-3"><label className="form-label fw-bold">Link Ảnh</label><input type="text" className="form-control" required onChange={(e) => setFormData({...formData, image: e.target.value})} /></div>
              {formData.image && <img src={formData.image} alt="Preview" className="mb-3 rounded" style={{maxHeight: '150px'}} />}
              <div className="mb-4"><label className="form-label fw-bold">Mô tả</label><textarea className="form-control" rows="5" required onChange={(e) => setFormData({...formData, description: e.target.value})}></textarea></div>
              <button type="submit" className="btn btn-chotot w-100 fw-bold py-3 fs-5">ĐĂNG TIN NGAY</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default PostProductPage;
